    """Run a git command and return the output."""
    result = subprocess.run(command, capture_output=True, text=True, shell=True, check=True)
    return result.stdout.strip()

def get_commit_history():
    """Get the commit history with hashes, authors, and dates."""
    log_format = '--pretty=format:"%h%x09%an%x09%ad" --date=short'
    git_log = run_git_command(f'git log {log_format}')
    commits = [line.split('\t') for line in git_log.split('\n')]
    return [(commit[0].strip('"'), commit[1], commit[2]) for commit in commits]

def get_author_commit_counts(commits):
    """Count the number of commits per author."""
    authors = [commit[1] for commit in commits]
    return Counter(authors)

def get_daily_commit_activity(commits):
    """Analyze daily commit activity."""
    dates = [commit[2] for commit in commits]
    return Counter(dates)

def get_file_changes():
    """Get the number of changes made to each file."""
    git_changes = run_git_command('git log --name-only --pretty=format:').split('\n')
    file_changes = Counter(filter(None, git_changes))
    return file_changes

