    themes = defaultdict(int)
    keywords = ['fix', 'add', 'update', 'remove', 'refactor', 'merge']

    for message in messages:
        lower_message = message.lower()
        for keyword in keywords:
            if keyword in lower_message:
                themes[keyword] += 1

    return themes

def main():
